UPDATE challenges SET description_en = 'Mauro Colagreco''s Mirazur earned #1 World''s Best Restaurant 2019 with three Michelin stars—nestled on a cliff above Menton, where France meets Italy. The restaurant''s terraced gardens supply vegetables, citrus, and herbs; the Mediterranean supplies fish. Colagreco''s cuisine celebrates the "three gardens": sea, mountain, and cultivated. Dishes are poetic and precise. Selected for our World 100 as the perfect union of place, produce, and culinary vision.' WHERE category = 'restaurants' AND title_en = 'Mirazur';

UPDATE challenges SET description_en = 'Alain Passard''s Arpège holds three Michelin stars and pioneered vegetable-centered fine dining in Paris. In 2001, Passard removed meat from his menu—a radical move—and devoted himself to his biodynamic farms in Normandy and Brittany. Today, vegetables are the stars: tomatoes in countless varieties, beet carpaccio, carrot tartare. Selected for our World 100 as the restaurant that proved vegetables could carry three Michelin stars.' WHERE category = 'restaurants' AND title_en = 'Arpège';

UPDATE challenges SET description_en = 'Guy Savoy''s eponymous restaurant holds three Michelin stars at the Monnaie de Paris—the French mint—on the Seine. Savoy''s classic French cuisine represents decades of refinement: artichoke soup with black truffle, roasted duck, millefeuille. The neo-Renaissance setting is opulent; the service is flawless. Selected for our World 100 as the living heritage of French gastronomy and Savoy''s enduring mastery.' WHERE category = 'restaurants' AND title_en = 'Guy Savoy';

UPDATE challenges SET description_en = 'Eric Frechon''s Epicure at Le Bristol Paris holds three Michelin stars in the city''s most luxurious palace hotel. The dining room overlooks a formal garden; the cuisine is pure French luxury: truffled langoustine, Bresse chicken, macaroni stuffed with black truffle and foie gras. Frechon has defined Parisian fine dining for a generation. Selected for our World 100 as the apex of Parisian palace dining.' WHERE category = 'restaurants' AND title_en = 'Epicure (Le Bristol)';

UPDATE challenges SET description_en = 'Pierre Gagnaire holds three Michelin stars in Paris and has redefined creative French cuisine since 1996. His "collage" approach juxtaposes flavors and textures that shouldn''t work—but do: sweet and savory, hot and cold, classic and avant-garde. Gagnaire''s influence spans the globe through his restaurants and protégés. Selected for our World 100 as the poet of contemporary French gastronomy.' WHERE category = 'restaurants' AND title_en = 'Pierre Gagnaire';

