UPDATE challenges SET description_en = 'Sven Elverfeld''s Aqua holds three Michelin stars in Wolfsburg—Germany''s unexpected fine dining capital. The Volkswagen city hosts this temple of modern German cuisine: precise, creative, ingredient-focused. Elverfeld''s tasting menus surprise and delight. Selected for our World 100 as Germany''s finest restaurant in its most surprising location.' WHERE category = 'restaurants' AND title_en = 'Aqua';

UPDATE challenges SET description_en = 'Joachim Wissler''s Vendôme holds three Michelin stars in Bergisch Gladbach—Germany''s grand cuisine pinnacle near Cologne. Wissler''s cuisine blends French technique with German ingredients: Rhine carp, venison, wild herbs. The setting is a castle; the cooking is world-class. Selected for our World 100 as Germany''s most accomplished fine dining.' WHERE category = 'restaurants' AND title_en = 'Vendôme';

UPDATE challenges SET description_en = 'Peter Goossens'' Hof van Cleve holds three Michelin stars in Kruishoutem—Belgium''s gastronomic peak. Goossens showcases Flemish ingredients: North Sea fish, Belgian beef, local vegetables. The farmhouse setting is rustic; the cuisine is refined. Selected for our World 100 as Belgium''s greatest restaurant.' WHERE category = 'restaurants' AND title_en = 'Hof van Cleve';

UPDATE challenges SET description_en = 'Jonnie Boer''s De Librije holds three Michelin stars in a converted prison in Zwolle—Netherlands'' most innovative restaurant. Boer''s cuisine is creative and technical: fermentations, distillations, bold flavors. The prison setting is dramatic; the cooking is groundbreaking. Selected for our World 100 as the Netherlands'' most creative fine dining.' WHERE category = 'restaurants' AND title_en = 'De Librije';

UPDATE challenges SET description_en = 'Björn Frantzén''s eponymous restaurant holds three Michelin stars in Stockholm—Sweden''s finest dining. Frantzén''s Japanese-Nordic fusion is precise and inventive: Swedish ingredients, Japanese technique, Nordic sensibility. The townhouse setting is intimate. Selected for our World 100 as the pinnacle of Nordic fine dining and Japan-Sweden fusion.' WHERE category = 'restaurants' AND title_en = 'Frantzén';

